import{_ as a}from"./Menu.edeb1320.js";import{u as o}from"./composables.4a9b2b71.js";import{r as e,a as n,e as l,b as c,f as i,o as d}from"./entry.787c95cd.js";const u=""+new URL("happy-dreche-adli.864f311f.jpg",import.meta.url).href,p=""+new URL("happy-dreche-figma.77045fa6.jpg",import.meta.url).href,m={class:"banniere"},h=i('<div class="margium-l marge-haute-l"><h1>Happy Dr\xEAche</h1><div class="colonnes"><div class="colonne"><div class="projettitre">Contexte</div> Contrat freelance : refonte de siteweb </div><div class="colonne"><div class="projettitre">Technologie</div> Figma, Wordpress, Gutenberg, Leaflet js, Matomo </div><div class="colonne"><div class="projettitre">P\xE9riode</div> janvier \xE0 f\xE9vrier 2022 </div><div class="colonne"><a href="https://happydreche.fr" class="lienapp" target="_blank">Visiter le site</a></div></div></div>',1),f=i('<article class="margium-l marge-haute-l marge-basse-l"><div class="espacium"><div class="coldroite"><p>Happy Dr\xEAche est une association lilloise cr\xE9\xE9e en 2018, elle lutte contre le gaspillage alimentaire d\u2019une ressource m\xE9connue : la dr\xEAche de brasserie. La dr\xEAche est collect\xE9e aupr\xE8s de brasseurs artisanaux de la m\xE9tropole et transform\xE9e pour composer des recettes gourmandes, saines et locales, distribu\xE9es en circuit court. Les produits propos\xE9s : snacking ap\xE9ro, c\xE9r\xE9ales, petit d\xE9jeuner, biscuits. </p><h2>Le brief </h2><p> Happy Dr\xEAche disposait d\u2019un site web sur la plateforme Wix.com, ce dernier n\xE9cessitait une refonte afin d\u2019am\xE9liorer son attractivit\xE9, sa lisibilit\xE9 et l\u2019acc\xE8s rapide aux informations prioritaires : produits disponibles, lieux de vente, \xE9v\xE9nements, contacts. <ul><li> Optimisation de l&#39;architecture de l&#39;information </li><li> Respect de la charte graphique (logo, colorim\xE9trie, polices) </li><li> Acc\xE9l\xE9ration du site et am\xE9lioration de son r\xE9f\xE9rencement </li><li> Mettre en avant les r\xE9seaux sociaux de l&#39;association </li><li> Former les salari\xE9\xB7e\xB7s \xE0 l\u2019utilisation du site </li><li> Cartographier les points de vente </li><li> Mobile friendly et cross navigateurs </li><li> \xC9co-con\xE7u </li><li> RGPD friendly </li></ul></p><h2>Architecture de l&#39;information</h2><img src="'+u+'" loading="lazy" alt="Capture d&#39;\xE9cran de l&#39;atelier d&#39;architecture de l&#39;information du site Happy Dr\xEAche"><p>Pour visualiser et \xE9changer facilement sur les contenus et l&#39;arborescence du site, nous avons utilis\xE9 la m\xE9thode OOUX. Elle permet d&#39;identifier les contenus, donner leurs caract\xE9ristiques d&#39;objets (lien, type ...) et de les r\xE9partir dans des pages et des sections. Cette m\xE9thode it\xE9rative optimise le temps pass\xE9 sur l\u2019\xE9tablissement de l&#39;architecture de l&#39;information.</p><h2>Maquettes</h2><img src="'+p+'" loading="lazy" alt="Capture d&#39;\xE9cran d&#39;une partie des maquette Figma du site Happy Dr\xEAche"><p>Les maquettes du site, on \xE9tait r\xE9alis\xE9 sur Figma avec des composants, des auto-layouts, une librairie de style, une grille de 12 colonnes. Cette configuration est \xE9labor\xE9e pour uniformiser les styles pour le d\xE9veloppement et de gagner du temps sur les modifications courantes : changer le style des titres N2, modifier l&#39;ordre des liens dans le pied de page... Pour les retours sur les maquettes, le commanditaire pouvait ajouter des commentaires sur les pages, ce qui fluidifie les \xE9changes sur les modifications \xE0 apporter. </p><h2>Choix techniques</h2><p>Le site a fait l&#39;objet d&#39;une veille technologique, pour choisir le CMS qui allait \xEAtre utilis\xE9 par l&#39;association. Le CMS WordPress pr\xE9sente un back-office tr\xE8s int\xE9ressant, facile \xE0 g\xE9rer et complet, notamment avec Gutenberg, un \xE9diteur de page intuitif, l\xE9ger et libre. Ce back-office r\xE9pondait plus aux besoins de gestion ind\xE9pendante du site, de plus c&#39;est celui qui n\xE9cessitait le moins de temps de production. Pour \xEAtre en ad\xE9quation avec les valeurs de l&#39;association, nous avons choisi d&#39;utiliser des logiciels libres ou avec des licences tr\xE8s permissives de type MIT ou GNU. Le th\xE8me WordPress a \xE9t\xE9 cr\xE9\xE9 sur mesure, ce qui lui permet d&#39;\xEAtre \xE0 100% optimis\xE9s, ne pas avoir de d\xE9pendance inutile, ni de codes non utilis\xE9s. <br><br> Pour comprendre les usages du site et les parcours utilisateurs, nous avons choisi l&#39;outil Matomo qui est un outil libre et auto-h\xE9berg\xE9 ce qui permet \xE0 l&#39;association de poss\xE9der et de ces donn\xE9es de visite et d&#39;utilisation, ce dernier est configur\xE9 pour ne pas d\xE9poser de cookies et d&#39;anonymiser les IP. Il n&#39;y a pas d&#39;autres scripts de tra\xE7age, ce qui permet une meilleure protection de la vie priv\xE9e des utilisateurs du site et de s&#39;affranchir de bandeau de consentement intrusif. Ces donn\xE9es sont utilis\xE9es pour appuyer l\u2019am\xE9lioration continue. <br><br> Pour la carte des points de vente, nous avons utilis\xE9 Leaflet JS qui nous accorde une grande personnalisation de la carte, sur son apparence, sur les lieux, par exemple, on a choisi de mettre des ic\xF4nes diff\xE9rentes pour les types de produit, sachets ou vrac. <br><br>Le r\xE9f\xE9rencement de ce site a eu recourt \xE0 l&#39;extension Yoast a \xE9t\xE9 employ\xE9 pour mettre des titres int\xE9ressants du point de vue des recherches effectu\xE9es par les utilisateurs. Le sitemap du site a \xE9t\xE9 d\xE9clar\xE9 aux moteurs Google et Bing (index d&#39;\xC9cosia, Qwant et Duckduckgo) pour une meilleure couverture d&#39;indexation. </p></div></div></article>',1),q={__name:"happy-dreche",setup(v){const s=e("Happy Dr\xEAche - Lucas Lacroix"),t=e("ce dernier n\xE9cessitait une refonte afin d\u2019am\xE9liorer son attractivit\xE9, sa lisibilit\xE9 et l\u2019acc\xE8s rapide aux informations prioritaires : produits disponibles, lieux de vente, \xE9v\xE9nements, contacts");return o({title:s,meta:[{name:"description",content:t}]}),(g,b)=>{const r=a;return d(),n("div",null,[l("div",m,[c(r),h]),f])}}};export{q as default};
